DROP TABLE IF EXISTS NAME_GENDER_mcv;

-- Create MCV table for NAME.GENDER, with a unique mcv_id
CREATE TABLE NAME_GENDER_mcv AS
WITH base AS (
    SELECT GENDER, COUNT(*) AS freq
    FROM NAME
    WHERE GENDER IS NOT NULL
    GROUP BY GENDER
    ORDER BY freq DESC
    LIMIT 5000
)
SELECT
    ROW_NUMBER() OVER (ORDER BY freq DESC) AS mcv_id,
    GENDER,
    freq
FROM base;

DROP TABLE IF EXISTS NAME_NAME_mcv;

-- Create MCV table for NAME.NAME, with a unique mcv_id
CREATE TABLE NAME_NAME_mcv AS
WITH base AS (
    SELECT NAME, COUNT(*) AS freq
    FROM NAME
    WHERE NAME IS NOT NULL
    GROUP BY NAME
    ORDER BY freq DESC
    LIMIT 5000
)
SELECT
    ROW_NUMBER() OVER (ORDER BY freq DESC) AS mcv_id,
    NAME,
    freq
FROM base;

DROP TABLE IF EXISTS NAME_NAME_PCODE_CF_mcv;

-- Create MCV table for NAME.NAME_PCODE_CF, with a unique mcv_id
CREATE TABLE NAME_NAME_PCODE_CF_mcv AS
WITH base AS (
    SELECT NAME_PCODE_CF, COUNT(*) AS freq
    FROM NAME
    WHERE NAME_PCODE_CF IS NOT NULL
    GROUP BY NAME_PCODE_CF
    ORDER BY freq DESC
    LIMIT 5000
)
SELECT
    ROW_NUMBER() OVER (ORDER BY freq DESC) AS mcv_id,
    NAME_PCODE_CF,
    freq
FROM base;

