-- Create aggregator table Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID for Histogram AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR -- FKPK_RANGE
