DROP TABLE IF EXISTS Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_EPISODE_NR_MOVIE_ID;

-- Create aggregator table Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_EPISODE_NR_MOVIE_ID for Histogram AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR -- FKPK_RANGE
CREATE TEMP TABLE Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_EPISODE_NR_MOVIE_ID AS
SELECT
    AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR AS EPISODE_NR,
    AKA_TITLE_MOVIE_ID_ID_TITLE.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM AKA_TITLE_MOVIE_ID_ID_TITLE

WHERE AKA_TITLE_MOVIE_ID_ID_TITLE.MOVIE_ID IS NOT NULL
GROUP BY
    AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR, AKA_TITLE_MOVIE_ID_ID_TITLE.MOVIE_ID
