DROP TABLE IF EXISTS Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID;

-- Create aggregator table Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID for MCV AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_TITLE -- FKPK_MCV
CREATE TEMP TABLE Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID AS KIND_ID,
    COUNT(*) AS deg
FROM AKA_TITLE_MOVIE_ID_ID_TITLE
JOIN TITLE_TITLE_mcv mcvt ON AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_TITLE = mcvt.TITLE
WHERE AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'AKA_TITLE' AS relation_name,
    'KIND_ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'TITLE' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID;

-- Create aggregator table Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID for NONMCV AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_TITLE -- FKPK_MCV
CREATE TEMP TABLE Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID AS
SELECT
    AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_TITLE AS TITLE,
    AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID AS KIND_ID,
    COUNT(*) AS deg
FROM AKA_TITLE_MOVIE_ID_ID_TITLE
LEFT JOIN TITLE_TITLE_mcv mcvt ON AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_TITLE = mcvt.TITLE
WHERE AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_TITLE, AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID
;

-- Insert into norms for Non-MCV AKA_TITLE_MOVIE_ID_ID_TITLE TITLE KIND_ID NONMCV
-- Among all non-MCV values in Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID, find max of each Lp
WITH perValue AS (
  SELECT
    TITLE,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_TITLE_KIND_ID
  GROUP BY TITLE
  HAVING TITLE IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'AKA_TITLE' AS relation_name,
    'KIND_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'TITLE' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

DROP TABLE IF EXISTS Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_EPISODE_NR_KIND_ID;

-- Create aggregator table Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_EPISODE_NR_KIND_ID for Histogram AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR -- FKPK_RANGE
CREATE TEMP TABLE Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_EPISODE_NR_KIND_ID AS
SELECT
    AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR AS EPISODE_NR,
    AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID AS KIND_ID,
    COUNT(*) AS deg
FROM AKA_TITLE_MOVIE_ID_ID_TITLE

WHERE AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID IS NOT NULL
GROUP BY
    AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR, AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID
;

INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'AKA_TITLE' AS relation_name,
    'KIND_ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'EPISODE_NR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        KIND_ID, bucket_id, SUM(deg) as deg
        FROM Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_EPISODE_NR_KIND_ID d
        JOIN TITLE_EPISODE_NR_histogram h
        ON (h.lower_bound IS NULL OR d.EPISODE_NR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.EPISODE_NR <= h.upper_bound)
    WHERE KIND_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY KIND_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_KIND_ID;

-- Create aggregator table Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_KIND_ID for Histogram AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR -- FKPK_RANGE
CREATE TEMP TABLE Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_KIND_ID AS
SELECT
    AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR AS PRODUCTION_YEAR,
    AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID AS KIND_ID,
    COUNT(*) AS deg
FROM AKA_TITLE_MOVIE_ID_ID_TITLE

WHERE AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID IS NOT NULL
GROUP BY
    AKA_TITLE_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR, AKA_TITLE_MOVIE_ID_ID_TITLE.KIND_ID
;

INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'AKA_TITLE' AS relation_name,
    'KIND_ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'PRODUCTION_YEAR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        KIND_ID, bucket_id, SUM(deg) as deg
        FROM Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_KIND_ID d
        JOIN TITLE_PRODUCTION_YEAR_histogram h
        ON (h.lower_bound IS NULL OR d.PRODUCTION_YEAR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.PRODUCTION_YEAR <= h.upper_bound)
    WHERE KIND_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY KIND_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

----------------------------------
-- START: generate all lpnorm queries for CAST_INFO
----------------------------------


DROP TABLE IF EXISTS CAST_INFO_MOVIE_ID_ID_TITLE;

-- Create temp table CAST_INFO_MOVIE_ID_ID_TITLE (FK->PK join)
CREATE TEMP TABLE CAST_INFO_MOVIE_ID_ID_TITLE AS
SELECT
    CAST_INFO.ID AS ID, CAST_INFO.PERSON_ID AS PERSON_ID, CAST_INFO.MOVIE_ID AS MOVIE_ID, CAST_INFO.PERSON_ROLE_ID AS PERSON_ROLE_ID, CAST_INFO.ROLE_ID AS ROLE_ID,
    TITLE.TITLE AS TITLE_TITLE, TITLE.PRODUCTION_YEAR AS TITLE_PRODUCTION_YEAR, TITLE.EPISODE_NR AS TITLE_EPISODE_NR
FROM CAST_INFO
JOIN TITLE
  ON CAST_INFO.MOVIE_ID = TITLE.ID
;

DROP TABLE IF EXISTS CAST_INFO_PERSON_ID_ID_NAME;

-- Create temp table CAST_INFO_PERSON_ID_ID_NAME (FK->PK join)
CREATE TEMP TABLE CAST_INFO_PERSON_ID_ID_NAME AS
SELECT
    CAST_INFO.ID AS ID, CAST_INFO.PERSON_ID AS PERSON_ID, CAST_INFO.MOVIE_ID AS MOVIE_ID, CAST_INFO.PERSON_ROLE_ID AS PERSON_ROLE_ID, CAST_INFO.ROLE_ID AS ROLE_ID,
    NAME.GENDER AS NAME_GENDER, NAME.NAME AS NAME_NAME, NAME.NAME_PCODE_CF AS NAME_NAME_PCODE_CF
FROM CAST_INFO
JOIN NAME
  ON CAST_INFO.PERSON_ID = NAME.ID
;

DROP TABLE IF EXISTS CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME;

-- Create temp table CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME (FK->PK join)
CREATE TEMP TABLE CAST_INFO_PERSON_ROLE_ID_ID_CHAR_NAME AS
SELECT
    CAST_INFO.ID AS ID, CAST_INFO.PERSON_ID AS PERSON_ID, CAST_INFO.MOVIE_ID AS MOVIE_ID, CAST_INFO.PERSON_ROLE_ID AS PERSON_ROLE_ID, CAST_INFO.ROLE_ID AS ROLE_ID,
    CHAR_NAME.NAME AS CHAR_NAME_NAME
FROM CAST_INFO
JOIN CHAR_NAME
  ON CAST_INFO.PERSON_ROLE_ID = CHAR_NAME.ID
;

DROP TABLE IF EXISTS CAST_INFO_ROLE_ID_ID_ROLE_TYPE;

-- Create temp table CAST_INFO_ROLE_ID_ID_ROLE_TYPE (FK->PK join)
CREATE TEMP TABLE CAST_INFO_ROLE_ID_ID_ROLE_TYPE AS
SELECT
    CAST_INFO.ID AS ID, CAST_INFO.PERSON_ID AS PERSON_ID, CAST_INFO.MOVIE_ID AS MOVIE_ID, CAST_INFO.PERSON_ROLE_ID AS PERSON_ROLE_ID, CAST_INFO.ROLE_ID AS ROLE_ID,
    ROLE_TYPE.ROLE AS ROLE_TYPE_ROLE
FROM CAST_INFO
JOIN ROLE_TYPE
  ON CAST_INFO.ROLE_ID = ROLE_TYPE.ID
;

DROP TABLE IF EXISTS Degree_CAST_INFO_ID;

-- Create aggregator table Degree_CAST_INFO_ID
CREATE TEMP TABLE Degree_CAST_INFO_ID AS
SELECT
    CAST_INFO.ID AS ID,
    COUNT(*) AS deg
FROM CAST_INFO

WHERE CAST_INFO.ID IS NOT NULL
GROUP BY
    CAST_INFO.ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

