CREATE TEMP TABLE Degree_CAST_INFO_PERSON_ID_ID_NAME_NAME_MOVIE_ID AS
SELECT
    CAST_INFO_PERSON_ID_ID_NAME.NAME_NAME AS NAME,
    CAST_INFO_PERSON_ID_ID_NAME.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM CAST_INFO_PERSON_ID_ID_NAME
LEFT JOIN NAME_NAME_mcv mcvt ON CAST_INFO_PERSON_ID_ID_NAME.NAME_NAME = mcvt.NAME
WHERE CAST_INFO_PERSON_ID_ID_NAME.MOVIE_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    CAST_INFO_PERSON_ID_ID_NAME.NAME_NAME, CAST_INFO_PERSON_ID_ID_NAME.MOVIE_ID
;

-- Insert into norms for Non-MCV CAST_INFO_PERSON_ID_ID_NAME NAME MOVIE_ID NONMCV
-- Among all non-MCV values in Degree_CAST_INFO_PERSON_ID_ID_NAME_NAME_MOVIE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    NAME,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_CAST_INFO_PERSON_ID_ID_NAME_NAME_MOVIE_ID
  GROUP BY NAME
  HAVING NAME IS NOT NULL
)
