-- Create aggregator table Degree_CAST_INFO_ROLE_ID_ID_ROLE_TYPE_ROLE_ROLE_ID for MCV CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_TYPE_ROLE -- FKPK_MCV
CREATE TEMP TABLE Degree_CAST_INFO_ROLE_ID_ID_ROLE_TYPE_ROLE_ROLE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_ID AS ROLE_ID,
    COUNT(*) AS deg
FROM CAST_INFO_ROLE_ID_ID_ROLE_TYPE
JOIN ROLE_TYPE_ROLE_mcv mcvt ON CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_TYPE_ROLE = mcvt.ROLE
WHERE CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'CAST_INFO' AS relation_name,
    'ROLE_ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'ROLE' AS pred_col_name,
    'ROLE_ID' AS fk_join_var_name,
    'ROLE_TYPE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_CAST_INFO_ROLE_ID_ID_ROLE_TYPE_ROLE_ROLE_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_CAST_INFO_ROLE_ID_ID_ROLE_TYPE_ROLE_ROLE_ID;

-- Create aggregator table Degree_CAST_INFO_ROLE_ID_ID_ROLE_TYPE_ROLE_ROLE_ID for NONMCV CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_TYPE_ROLE -- FKPK_MCV
CREATE TEMP TABLE Degree_CAST_INFO_ROLE_ID_ID_ROLE_TYPE_ROLE_ROLE_ID AS
SELECT
    CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_TYPE_ROLE AS ROLE,
    CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_ID AS ROLE_ID,
    COUNT(*) AS deg
FROM CAST_INFO_ROLE_ID_ID_ROLE_TYPE
LEFT JOIN ROLE_TYPE_ROLE_mcv mcvt ON CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_TYPE_ROLE = mcvt.ROLE
WHERE CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_TYPE_ROLE, CAST_INFO_ROLE_ID_ID_ROLE_TYPE.ROLE_ID
;

-- Insert into norms for Non-MCV CAST_INFO_ROLE_ID_ID_ROLE_TYPE ROLE ROLE_ID NONMCV
-- Among all non-MCV values in Degree_CAST_INFO_ROLE_ID_ID_ROLE_TYPE_ROLE_ROLE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    ROLE,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_CAST_INFO_ROLE_ID_ID_ROLE_TYPE_ROLE_ROLE_ID
  GROUP BY ROLE
  HAVING ROLE IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'CAST_INFO' AS relation_name,
    'ROLE_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'ROLE' AS pred_col_name,
    'ROLE_ID' AS fk_join_var_name,
    'ROLE_TYPE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

