DROP TABLE IF EXISTS Degree_CHAR_NAME_NAME_ID;

-- Create aggregator table Degree_CHAR_NAME_NAME_ID for MCV CHAR_NAME.NAME -- MCV
CREATE TEMP TABLE Degree_CHAR_NAME_NAME_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    CHAR_NAME.ID AS ID,
    COUNT(*) AS deg
FROM CHAR_NAME
JOIN CHAR_NAME_NAME_mcv mcvt ON CHAR_NAME.NAME = mcvt.NAME
WHERE CHAR_NAME.ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, CHAR_NAME.ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'CHAR_NAME' AS relation_name,
    'ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'NAME' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_CHAR_NAME_NAME_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_CHAR_NAME_NAME_ID;

-- Create aggregator table Degree_CHAR_NAME_NAME_ID for NONMCV CHAR_NAME.NAME -- MCV
CREATE TEMP TABLE Degree_CHAR_NAME_NAME_ID AS
SELECT
    CHAR_NAME.NAME AS NAME,
    CHAR_NAME.ID AS ID,
    COUNT(*) AS deg
FROM CHAR_NAME
LEFT JOIN CHAR_NAME_NAME_mcv mcvt ON CHAR_NAME.NAME = mcvt.NAME
WHERE CHAR_NAME.ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    CHAR_NAME.NAME, CHAR_NAME.ID
;

-- Insert into norms for Non-MCV CHAR_NAME NAME ID NONMCV
-- Among all non-MCV values in Degree_CHAR_NAME_NAME_ID, find max of each Lp
WITH perValue AS (
  SELECT
    NAME,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_CHAR_NAME_NAME_ID
  GROUP BY NAME
  HAVING NAME IS NOT NULL
)
