DROP TABLE IF EXISTS Degree_MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE_KIND_COMPANY_TYPE_ID;

-- Create aggregator table Degree_MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE_KIND_COMPANY_TYPE_ID for MCV MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_KIND -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE_KIND_COMPANY_TYPE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_ID AS COMPANY_TYPE_ID,
    COUNT(*) AS deg
FROM MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE
JOIN COMPANY_TYPE_KIND_mcv mcvt ON MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_KIND = mcvt.KIND
WHERE MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_ID
;

