DROP TABLE IF EXISTS Degree_MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE_KIND_COMPANY_TYPE_ID;

-- Create aggregator table Degree_MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE_KIND_COMPANY_TYPE_ID for NONMCV MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_KIND -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE_KIND_COMPANY_TYPE_ID AS
SELECT
    MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_KIND AS KIND,
    MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_ID AS COMPANY_TYPE_ID,
    COUNT(*) AS deg
FROM MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE
LEFT JOIN COMPANY_TYPE_KIND_mcv mcvt ON MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_KIND = mcvt.KIND
WHERE MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_KIND, MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE.COMPANY_TYPE_ID
;

-- Insert into norms for Non-MCV MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE KIND COMPANY_TYPE_ID NONMCV
-- Among all non-MCV values in Degree_MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE_KIND_COMPANY_TYPE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    KIND,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_MOVIE_COMPANIES_COMPANY_TYPE_ID_ID_COMPANY_TYPE_KIND_COMPANY_TYPE_ID
  GROUP BY KIND
  HAVING KIND IS NOT NULL
)
