DROP TABLE IF EXISTS Degree_MOVIE_INFO_INFO_MOVIE_ID;

-- Create aggregator table Degree_MOVIE_INFO_INFO_MOVIE_ID for MCV MOVIE_INFO.INFO -- MCV
CREATE TEMP TABLE Degree_MOVIE_INFO_INFO_MOVIE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_INFO.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM MOVIE_INFO
JOIN MOVIE_INFO_INFO_mcv mcvt ON MOVIE_INFO.INFO = mcvt.INFO
WHERE MOVIE_INFO.MOVIE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_INFO.MOVIE_ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_INFO' AS relation_name,
    'MOVIE_ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'INFO' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_MOVIE_INFO_INFO_MOVIE_ID
GROUP BY mcv_id
;

