DROP TABLE IF EXISTS Degree_MOVIE_INFO_IDX_INFO_ID;

-- Create aggregator table Degree_MOVIE_INFO_IDX_INFO_ID for Histogram MOVIE_INFO_IDX.INFO -- RANGE
CREATE TEMP TABLE Degree_MOVIE_INFO_IDX_INFO_ID AS
SELECT
    MOVIE_INFO_IDX.INFO AS INFO,
    MOVIE_INFO_IDX.ID AS ID,
    COUNT(*) AS deg
FROM MOVIE_INFO_IDX

WHERE MOVIE_INFO_IDX.ID IS NOT NULL
GROUP BY
    MOVIE_INFO_IDX.INFO, MOVIE_INFO_IDX.ID
;

INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_INFO_IDX' AS relation_name,
    'ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'INFO' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        ID, bucket_id, SUM(deg) as deg
        FROM Degree_MOVIE_INFO_IDX_INFO_ID d
        JOIN MOVIE_INFO_IDX_INFO_histogram h
        ON (h.lower_bound IS NULL OR d.INFO >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.INFO <= h.upper_bound)
    WHERE ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID;

-- Create aggregator table Degree_MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID for MCV MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE.ID AS ID,
    COUNT(*) AS deg
FROM MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE
JOIN TITLE_PRODUCTION_YEAR_mcv mcvt ON MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR = mcvt.PRODUCTION_YEAR
WHERE MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE.ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE.ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_INFO_IDX' AS relation_name,
    'ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'PRODUCTION_YEAR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID
