    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        INFO_TYPE_ID, bucket_id, SUM(deg) as deg
        FROM Degree_MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_INFO_TYPE_ID d
        JOIN TITLE_PRODUCTION_YEAR_histogram h
        ON (h.lower_bound IS NULL OR d.PRODUCTION_YEAR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.PRODUCTION_YEAR <= h.upper_bound)
    WHERE INFO_TYPE_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY INFO_TYPE_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID;

-- Create aggregator table Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID for MCV MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID AS INFO_TYPE_ID,
    COUNT(*) AS deg
FROM MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE
JOIN INFO_TYPE_INFO_mcv mcvt ON MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO = mcvt.INFO
WHERE MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_INFO_IDX' AS relation_name,
    'INFO_TYPE_ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'INFO' AS pred_col_name,
    'INFO_TYPE_ID' AS fk_join_var_name,
    'INFO_TYPE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID;

-- Create aggregator table Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID for NONMCV MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID AS
SELECT
    MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO AS INFO,
    MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID AS INFO_TYPE_ID,
    COUNT(*) AS deg
FROM MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE
LEFT JOIN INFO_TYPE_INFO_mcv mcvt ON MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO = mcvt.INFO
WHERE MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO, MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_ID
;

-- Insert into norms for Non-MCV MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE INFO INFO_TYPE_ID NONMCV
-- Among all non-MCV values in Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    INFO,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_MOVIE_INFO_IDX_INFO_TYPE_ID_ID_INFO_TYPE_INFO_INFO_TYPE_ID
  GROUP BY INFO
  HAVING INFO IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_INFO_IDX' AS relation_name,
    'INFO_TYPE_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'INFO' AS pred_col_name,
    'INFO_TYPE_ID' AS fk_join_var_name,
    'INFO_TYPE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

