DROP TABLE IF EXISTS Degree_MOVIE_KEYWORD_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID;

-- Create aggregator table Degree_MOVIE_KEYWORD_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID for MCV MOVIE_KEYWORD_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_KEYWORD_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID AS
SELECT
