CREATE TEMP TABLE Degree_MOVIE_LINK_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_LINKED_MOVIE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_LINK_MOVIE_ID_ID_TITLE.LINKED_MOVIE_ID AS LINKED_MOVIE_ID,
    COUNT(*) AS deg
FROM MOVIE_LINK_MOVIE_ID_ID_TITLE
JOIN TITLE_PRODUCTION_YEAR_mcv mcvt ON MOVIE_LINK_MOVIE_ID_ID_TITLE.TITLE_PRODUCTION_YEAR = mcvt.PRODUCTION_YEAR
WHERE MOVIE_LINK_MOVIE_ID_ID_TITLE.LINKED_MOVIE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_LINK_MOVIE_ID_ID_TITLE.LINKED_MOVIE_ID
;

