-- Create aggregator table Degree_PERSON_INFO_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID for NONMCV PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF -- FKPK_MCV
CREATE TEMP TABLE Degree_PERSON_INFO_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID AS
SELECT
    PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF AS NAME_PCODE_CF,
    PERSON_INFO_PERSON_ID_ID_NAME.ID AS ID,
    COUNT(*) AS deg
FROM PERSON_INFO_PERSON_ID_ID_NAME
LEFT JOIN NAME_NAME_PCODE_CF_mcv mcvt ON PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF = mcvt.NAME_PCODE_CF
WHERE PERSON_INFO_PERSON_ID_ID_NAME.ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF, PERSON_INFO_PERSON_ID_ID_NAME.ID
;

-- Insert into norms for Non-MCV PERSON_INFO_PERSON_ID_ID_NAME NAME_PCODE_CF ID NONMCV
-- Among all non-MCV values in Degree_PERSON_INFO_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID, find max of each Lp
WITH perValue AS (
  SELECT
    NAME_PCODE_CF,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_PERSON_INFO_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID
  GROUP BY NAME_PCODE_CF
  HAVING NAME_PCODE_CF IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'PERSON_INFO' AS relation_name,
    'ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'NAME_PCODE_CF' AS pred_col_name,
    'PERSON_ID' AS fk_join_var_name,
    'NAME' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

DROP TABLE IF EXISTS Degree_PERSON_INFO_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID;

-- Create aggregator table Degree_PERSON_INFO_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID for Histogram PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF -- FKPK_RANGE
CREATE TEMP TABLE Degree_PERSON_INFO_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID AS
SELECT
    PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF AS NAME_PCODE_CF,
    PERSON_INFO_PERSON_ID_ID_NAME.ID AS ID,
    COUNT(*) AS deg
FROM PERSON_INFO_PERSON_ID_ID_NAME

WHERE PERSON_INFO_PERSON_ID_ID_NAME.ID IS NOT NULL
GROUP BY
    PERSON_INFO_PERSON_ID_ID_NAME.NAME_NAME_PCODE_CF, PERSON_INFO_PERSON_ID_ID_NAME.ID
;

INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'PERSON_INFO' AS relation_name,
    'ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'NAME_PCODE_CF' AS pred_col_name,
    'PERSON_ID' AS fk_join_var_name,
    'NAME' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        ID, bucket_id, SUM(deg) as deg
        FROM Degree_PERSON_INFO_PERSON_ID_ID_NAME_NAME_PCODE_CF_ID d
        JOIN NAME_NAME_PCODE_CF_histogram h
        ON (h.lower_bound IS NULL OR d.NAME_PCODE_CF >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.NAME_PCODE_CF <= h.upper_bound)
    WHERE ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

